import{_ as t,o as i,c as a,ag as s}from"./chunks/framework.CTpQozEL.js";const x=JSON.parse('{"title":"Perplexity (프로바이더)","description":"Perplexity 웹 검색 프로바이더 설정 (API 키, 검색 모드, 필터링)","frontmatter":{"title":"Perplexity (프로바이더)","description":"Perplexity 웹 검색 프로바이더 설정 (API 키, 검색 모드, 필터링)"},"headers":[],"relativePath":"providers/perplexity-provider.md","filePath":"providers/perplexity-provider.md","lastUpdated":null}'),l={name:"providers/perplexity-provider.md"};function r(o,e,p,n,d,h){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="perplexity-웹-검색-프로바이더" tabindex="-1">Perplexity (웹 검색 프로바이더) <a class="header-anchor" href="#perplexity-웹-검색-프로바이더" aria-label="Permalink to &quot;Perplexity (웹 검색 프로바이더)&quot;">​</a></h1><p>Perplexity 플러그인은 Perplexity Search API 또는 OpenRouter를 통한 Perplexity Sonar를 통해 웹 검색 기능을 제공합니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>이 페이지는 Perplexity <strong>프로바이더</strong> 설정을 다룹니다. Perplexity <strong>도구</strong> (에이전트가 이를 사용하는 방법)에 대해서는 <a href="/openclaw-docs-ko/tools/perplexity-search">Perplexity 도구</a>를 참조하십시오.</p></div><ul><li>유형: 웹 검색 프로바이더 (모델 프로바이더 아님)</li><li>인증: <code>PERPLEXITY_API_KEY</code> (직접) 또는 <code>OPENROUTER_API_KEY</code> (OpenRouter 경유)</li><li>구성 경로: <code>plugins.entries.perplexity.config.webSearch.apiKey</code></li></ul><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><ol><li>API 키 설정:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --section</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web</span></span></code></pre></div><p>또는 직접 설정:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins.entries.perplexity.config.webSearch.apiKey</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;pplx-xxxxxxxxxxxx&quot;</span></span></code></pre></div><ol start="2"><li>구성되면 에이전트가 자동으로 웹 검색에 Perplexity를 사용합니다.</li></ol><h2 id="검색-모드" tabindex="-1">검색 모드 <a class="header-anchor" href="#검색-모드" aria-label="Permalink to &quot;검색 모드&quot;">​</a></h2><p>플러그인은 API 키 접두사에 따라 전송을 자동으로 선택합니다:</p><table tabindex="0"><thead><tr><th>키 접두사</th><th>전송</th><th>기능</th></tr></thead><tbody><tr><td><code>pplx-</code></td><td>네이티브 Perplexity Search API</td><td>구조화된 결과, 도메인/언어/날짜 필터</td></tr><tr><td><code>sk-or-</code></td><td>OpenRouter (Sonar)</td><td>인용이 포함된 AI 합성 답변</td></tr></tbody></table><h2 id="네이티브-api-필터링" tabindex="-1">네이티브 API 필터링 <a class="header-anchor" href="#네이티브-api-필터링" aria-label="Permalink to &quot;네이티브 API 필터링&quot;">​</a></h2><p>네이티브 Perplexity API (<code>pplx-</code> 키) 사용 시 검색은 다음을 지원합니다:</p><ul><li><strong>국가</strong>: 2자리 국가 코드</li><li><strong>언어</strong>: ISO 639-1 언어 코드</li><li><strong>날짜 범위</strong>: 일, 주, 월, 년</li><li><strong>도메인 필터</strong>: 허용 목록/차단 목록 (최대 20개 도메인)</li><li><strong>콘텐츠 예산</strong>: <code>max_tokens</code>, <code>max_tokens_per_page</code></li></ul><h2 id="환경-참고-사항" tabindex="-1">환경 참고 사항 <a class="header-anchor" href="#환경-참고-사항" aria-label="Permalink to &quot;환경 참고 사항&quot;">​</a></h2><p>게이트웨이가 데몬(launchd/systemd)으로 실행되는 경우 해당 프로세스에서 <code>PERPLEXITY_API_KEY</code>를 사용할 수 있어야 합니다 (예: <code>~/.openclaw/.env</code> 또는 <code>env.shellEnv</code>를 통해).</p>',18)])])}const k=t(l,[["render",r]]);export{x as __pageData,k as default};
